        /// <param name="nlevels">The number of pyramid levels. The smallest level will have linear size equal to input_image_linear_size/pow(scaleFactor, nlevels - firstLevel).</param>
        /// <param name="edgeThreshold">This is size of the border where the features are not detected. It should roughly match the patchSize parameter.</param>
        /// <param name="firstLevel">The level of pyramid to put source image to. Previous layers are filled with upscaled source image.</param>
